import (
	"strings"
	"testing"
	"time"

	"github.com/iksnae/code-certification/internal/domain"
)

// testRecord builds a minimal CertificationRecord for report tests.
func testRecord(lang, path, symbol string, score float64, status domain.Status) domain.CertificationRecord {
	return domain.CertificationRecord{
		UnitID:   domain.NewUnitID(lang, path, symbol),
		UnitType: domain.UnitTypeFunction,
		UnitPath: path,
		Score:    score,
		Grade:    domain.GradeFromScore(score),
		Status:   status,
		Dimensions: domain.DimensionScores{
			domain.DimCorrectness: score,
			domain.DimReadability: score,
		},
		CertifiedAt: time.Now().Add(-24 * time.Hour),
		ExpiresAt:   time.Now().Add(30 * 24 * time.Hour),
		Source:      "test",
	}
}

func TestCard_UnsupportedBanner(t *testing.T) {
	// Mix of supported (go) and unsupported (swift) records.
	records := []domain.CertificationRecord{
		testRecord("go", "pkg/foo.go", "FuncA", 0.95, domain.StatusCertified),
		testRecord("swift", "pkg/bar.swift", "FuncB", 0.80, domain.StatusCertified),
		testRecord("go", "pkg/baz.go", "FuncC", 0.60, domain.StatusCertifiedWithObservations),
		testRecord("swift", "pkg/qux.swift", "FuncD", 0.45, domain.StatusDecertified),
	}

	card := GenerateCard(records, "github.com/foo", "abc1234", time.Now())

	if card.UnsupportedCount == 0 {
		t.Error("expected UnsupportedCount > 0 for records with unsupported languages")
	}
	if len(card.UnsupportedLanguages) == 0 {
		t.Error("expected UnsupportedLanguages to be populated")
	}
	hasSwift := false
	for _, lang := range card.UnsupportedLanguages {
		if lang == "swift" {
			hasSwift = true
			break
		}
	}
	if !hasSwift {
		t.Errorf("expected UnsupportedLanguages to contain 'swift', got %v", card.UnsupportedLanguages)
	}

	// Verify formatted text includes an unsupported-languages banner section.
	text := FormatCardText(card)
	if !strings.Contains(text, "Unsupported") && !strings.Contains(text, "unsupported") {
		t.Error("expected formatted card text to mention unsupported languages")
	}
}

func TestCard_NAAGradeRendering(t *testing.T) {
	// Empty records → overall grade should be N/A.
	card := GenerateCard(nil, "github.com/foo", "abc1234", time.Now())

	if card.OverallGrade != "N/A" {
		t.Errorf("expected OverallGrade 'N/A' for empty records, got %q", card.OverallGrade)
	}

	text := FormatCardText(card)
	if !strings.Contains(text, "N/A") {
		t.Error("expected formatted card text to contain 'N/A'")
	}

	md := FormatCardMarkdown(card)
	if !strings.Contains(md, "N/A") {
		t.Error("expected markdown card to contain 'N/A'")
	}
}

func TestCard_AnalyzableUnits(t *testing.T) {
	records := []domain.CertificationRecord{
		testRecord("go", "pkg/foo.go", "FuncA", 0.95, domain.StatusCertified),
		testRecord("swift", "pkg/bar.swift", "FuncB", 0.80, domain.StatusCertified),
		testRecord("go", "pkg/baz.go", "FuncC", 0.60, domain.StatusCertifiedWithObservations),
	}

	card := GenerateCard(records, "github.com/foo", "abc1234", time.Now())

	// AnalyzableUnits should count only supported-language records.
	if card.AnalyzableUnits == 0 {
		t.Error("expected AnalyzableUnits > 0")
	}
	if card.AnalyzableUnits > card.TotalUnits {
		t.Errorf("AnalyzableUnits (%d) should not exceed TotalUnits (%d)", card.AnalyzableUnits, card.TotalUnits)
	}
	// With 2 go (supported) and 1 swift (unsupported), analyzable should be 2.
	if card.AnalyzableUnits != 2 {
		t.Errorf("expected AnalyzableUnits=2 (only go records), got %d", card.AnalyzableUnits)
	}
}

func TestFull_BuildLanguageDetailExcludesUnsupported(t *testing.T) {
	records := []domain.CertificationRecord{
		testRecord("go", "pkg/foo.go", "FuncA", 0.95, domain.StatusCertified),
		testRecord("swift", "pkg/bar.swift", "FuncB", 0.80, domain.StatusCertified),
		testRecord("go", "pkg/baz.go", "FuncC", 0.60, domain.StatusCertifiedWithObservations),
		testRecord("swift", "pkg/qux.swift", "FuncD", 0.45, domain.StatusDecertified),
	}

	full := GenerateFullReport(records, "github.com/foo", "abc1234", time.Now())

	// LanguageDetail should NOT include unsupported languages.
	for _, ld := range full.LanguageDetail {
		if ld.Name == "swift" {
			t.Error("expected LanguageDetail to exclude unsupported language 'swift'")
		}
	}

	// DimensionAverages should only reflect supported-language units.
	if len(full.DimensionAverages) == 0 {
		t.Error("expected DimensionAverages to be non-empty")
	}
}

func TestFull_AggregateScoreExcludesUnsupported(t *testing.T) {
	// Two supported go records with high scores, two unsupported swift with low scores.
	records := []domain.CertificationRecord{
		testRecord("go", "pkg/foo.go", "FuncA", 0.95, domain.StatusCertified),
		testRecord("go", "pkg/bar.go", "FuncB", 0.85, domain.StatusCertified),
		testRecord("swift", "pkg/baz.swift", "FuncC", 0.10, domain.StatusDecertified),
		testRecord("swift", "pkg/qux.swift", "FuncD", 0.05, domain.StatusDecertified),
	}

	card := GenerateCard(records, "github.com/foo", "abc1234", time.Now())

	// If unsupported records were excluded from aggregate, overall score
	// should reflect only the go records (avg 0.90), not the swift ones.
	// If all 4 were averaged: (0.95+0.85+0.10+0.05)/4 = 0.4875
	// If only 2 go: (0.95+0.85)/2 = 0.90
	if card.OverallScore < 0.85 {
		t.Errorf("expected aggregate score >= 0.85 (based on supported only), got %.3f", card.OverallScore)
	}
}

