func TestScorer_NAAGradeIsNoOp(t *testing.T) {
	// Pass evidence with an unsupported (N/A-grade) language through the scorer.
	// The scorer must not panic and should return nil for TierGeneric languages.
	ev := []domain.Evidence{
		evidence.LintResult{Tool: "eslint", ErrorCount: 0}.ToEvidence(),
		evidence.TestResult{Tool: "jest", TotalCount: 5, PassedCount: 5, Coverage: 0.8}.ToEvidence(),
		evidence.CodeMetrics{TotalLines: 100, CodeLines: 80, Complexity: 5}.ToEvidence(),
	}

	evalResult := policy.EvaluationResult{Passed: true}

	// Use an unsupported language — must not panic
	scores := engine.Score(ev, evalResult, "swift")
	if scores != nil {
		t.Errorf("expected nil scores for N/A-grade language, got %d dimensions", len(scores))
	}
}

